def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}

    # Tier N requires N documents on file and N passed checks before approval.
    REQUIRED = {1: 1, 2: 2, 3: 3}
    tier = int(s.get("requested_tier", 1))
    if tier not in REQUIRED:
        tier = 1
        s["requested_tier"] = 1
    need = REQUIRED[tier]

    stage = s.get("stage", "onboarding")

    # 'approved' and 'rejected' are absorbing: nothing changes once decided.
    if stage in ("approved", "rejected"):
        return s

    if name == "submit_docs":
        # File one document per call, capped at the requested tier's requirement.
        if stage in ("onboarding", "submitted"):
            s["docs_count"] = min(need, int(s.get("docs_count", 0)) + 1)
            s["stage"] = "submitted"

    elif name == "verify":
        # Run one check per call (always an attempt); a check can only clear
        # while a supporting document is already on file.
        if stage in ("submitted", "verifying"):
            s["attempts"] = int(s.get("attempts", 0)) + 1
            if int(s.get("checks_passed", 0)) < int(s.get("docs_count", 0)):
                s["checks_passed"] = int(s.get("checks_passed", 0)) + 1
            if (int(s.get("checks_passed", 0)) >= need
                    and int(s.get("docs_count", 0)) >= need):
                s["stage"] = "verified"
            else:
                s["stage"] = "verifying"

    elif name == "approve":
        # Approval only from a fully verified application; grants the tier.
        if stage == "verified":
            s["stage"] = "approved"
            s["granted_tier"] = tier
            s["decision_reason"] = "tier " + str(tier) + " checks satisfied"

    elif name == "reject":
        # Allowed from any non-terminal stage; grants no tier.
        s["stage"] = "rejected"
        s["granted_tier"] = 0
        s["decision_reason"] = str(params.get("reason", "verification not satisfied"))

    return s

