def perceive(data):
    if isinstance(data, str):
        fields = {}
        for line in data.splitlines():
            if ":" in line:
                k, v = line.split(":", 1)
                fields[k.strip().lower()] = v.strip()
    else:
        fields = {str(k).lower(): v for k, v in dict(data).items()}

    out = {}
    tier = fields.get("tier")
    if tier is None:
        tier = fields.get("requested_tier")
    if tier is not None:
        try:
            out["requested_tier"] = max(1, min(3, int(tier)))
        except (ValueError, TypeError):
            pass

    docs = fields.get("documents")
    if docs is None:
        docs = fields.get("docs")
    if docs is None:
        docs = fields.get("doc_count")
    if docs is not None:
        try:
            out["docs_count"] = max(0, min(3, int(docs)))
        except (ValueError, TypeError):
            pass

    return out
